                hint="Pick Tail Layer"
                persistent-hint
              ></v-select>
            </v-col>

            <v-col xl="2" lg="2" md="6" sm="6" cols="6">
              <v-subheader class="pl-2">Keep Layers</v-subheader>
              <v-select
                v-model="keepLayer"
                :items="keepLayers"
                :menu-props="{ maxHeight: '400' }"
                hint="Keep Layers"
                persistent-hint
              ></v-select>
            </v-col>    
          </v-row>
          <v-row>
            <v-toolbar flat color="primary" dark>
              <v-toolbar-title>IBO Commission</v-toolbar-title>      
            </v-toolbar>
          </v-row>
          <v-row>
            <v-col xl="2" lg="2" md="6" sm="6" cols="6">
              <v-subheader class="pl-2">Total Payment</v-subheader>
              <v-text-field
                :value="totalPayment"
                label="JPY"
                prefix="￥"
                readonly
              ></v-text-field>
            </v-col>

            <v-col xl="2" lg="2" md="6" sm="6" cols="6">
              <v-subheader class="pl-2">Commission / Total Payment</v-subheader>
              <v-text-field
                :value="Math.round(totalCommission / totalPayment * 10000) / 100"
                prefix="%"
