            </v-col>

            <v-col xl="2" lg="2" md="6" sm="6" cols="6">
              <v-subheader class="pl-2">2nd Year Income</v-subheader>
              <v-text-field
                :value="totalCommission * 12 - iboRenewalFee * keepLayer"
                label="JPY"
                prefix="￥"
                readonly
              ></v-text-field>
            </v-col>          
          </v-row>                
          
        </v-expansion-panel-content>
      </v-expansion-panel>
      <v-expansion-panel>
        <v-expansion-panel-header>
          <span>
            <v-icon left>mdi-chart-bar-stacked</v-icon>
            Charts
          </span>
        </v-expansion-panel-header>
        <v-expansion-panel-content>
          <v-row>
            <v-toolbar flat color="primary" dark>
              <v-toolbar-title>Commission Details</v-toolbar-title>      
            </v-toolbar>            
          </v-row>
