              />
            </v-col>
          </v-row> -->
          <v-row>       
            <v-col xl="12" lg="12" md="12" sm="12" cols="12">
              <apexchart height="300" :options="apexChartOption" :series="apexChartData"></apexchart>
            </v-col>
          </v-row>          
<!--           <v-row>
            <v-toolbar flat color="primary" dark>
              <v-toolbar-title>Multiple Layers</v-toolbar-title>      
            </v-toolbar>            
          </v-row>          
          <v-row>
            <v-col xl="12" lg="12" md="12" sm="12" cols="12">
              <div id="tree">
                <GChart
                  :settings="{ packages: ['orgchart'], callback: ()=>{this.drawChart(this.teamConfig)} }"
                  type="OrgChart"
                  :data="orgChartData"
