</template>

<script>
import { mapState, mapActions } from 'vuex'
// import { GChart } from 'vue-google-charts'
import VueApexCharts from 'vue-apexcharts'

export default {
	components: {
		// GChart,
    apexchart: VueApexCharts
	},
  data () {
    return {
      teamConfig: {
      },
    	// teamConfig: {
     //    layer: 7,
     //    percent: 8,
     //    from: 75,
     //  },
    	keepLayer: 2,
      min: 1,
      max: 100,
      personalHeaders: [
        { text: 'Commission Percentage', value: 'percent' },
        { text: 'Point From', value: 'from' },
        { text: 'Point To', value: 'to' },
      ],
      teamHeaders: [
        { text: 'Layer', value: 'layer' },
        { text: 'Commission Percentage', value: 'percent' },
        { text: 'Point From', value: 'from' },
      ],
      energyRate: 10000,
      energyCount: 100,
      mobileRate: 5000,
      mobileCount: 100,
      orgChartData: [],
      gcChartOptions: {
      	isStacked: true,
      	legend: {position: 'top', maxLines: 6},
      	height: 300
      },
    }
  },
  computed: {
    totalPayment: function () {
  		return this.energyRate * this.energyCount + this.mobileRate * this.mobileCount
    },  	
    keepLayers: function () {
    	return [2, 8]
    },
    commissionLayers: function () {
  		return this.teamConfigs.map(item => {
				return {
					label: `L${item.layer}: ${item.percent}%`,
					value: item
				}
			})
    },
    personalPercent: function () {

    	let headPersonalPoint = 0
    	let tailPersonalPoint = 0

    	if (this.energyCount > 0) {
    		headPersonalPoint += this.energyCount * this.pointEnergy
    	}

    	if (this.mobileCount > 0) {
    		headPersonalPoint += this.mobileCount * this.pointMobile
    	}

    	if (headPersonalPoint == 0) {
    		return {
    			head: 0,
    			tail: 0
    		}
    	}

    	if (this.teamCommissionPoint) {

    		if (headPersonalPoint > this.teamCommissionPoint) {

    			tailPersonalPoint = headPersonalPoint - this.teamCommissionPoint

    			headPersonalPoint = this.teamCommissionPoint

    			const tailPersonalConfig = this.getPersonalConfig(tailPersonalPoint)

    			const headPersonalConfig = this.getPersonalConfig(headPersonalPoint)

		    	return {
		    		head: headPersonalConfig.percent / 100,
		    		tail: tailPersonalConfig.percent / 100
		    	}
	    		
    		} else {

    			const headPersonalConfig = this.getPersonalConfig(headPersonalPoint)

		    	return {
		    		head: headPersonalConfig.percent / 100,
		    		tail: 0
		    	}
    		}

    	} else {

	    	const headPersonalConfig = this.getPersonalConfig(headPersonalPoint)

	    	return {
	    		head: headPersonalConfig.percent / 100,
	    		tail: 0
	    	}
    	}
    },          
    teamCommissionPoint: function () {
    	if (this.teamConfig) {
    		return this.teamConfig.from
    	}
    },    
    teamCommissionPercent: function () {
    	if (this.teamConfig) {
    		return this.teamConfig.percent / 100
    	}
    },
		headTailCounts: function() {
			return this.getHeadTailCounts()
		},
		headCommission: function() {
			return this.getHeadCommission(this.headTailCounts)
		},
		tailCommission: function() {
			return this.getTailCommission(this.headTailCounts)
		},
		totalCommission: function() {
			return this.getTotalCommissions()
		},		
		gcChartData: function() {
			return this.getGcChartData();
		},  
    apexChartOption: function() {
      return{
        chart: {
          type: 'bar',
          height: 350,
          stacked: true,
          toolbar: {
            show: true
          },
          zoom: {
            enabled: true
          }
        },
        responsive: [{
          breakpoint: 480,
          options: {
            legend: {
              position: 'bottom',
              offsetX: -10,
              offsetY: 0
            }
          }
        }],
        plotOptions: {
          bar: {
            horizontal: false,
          },
        },
        xaxis: {
          type: 'String',
          categories: ['Head', 'Tail', 'Total'],
        },
        legend: {
          position: 'top',
          offsetY: 0
        },
        fill: {
          opacity: 0.8
        }
      }
    },
    apexChartData: function() {
      return this.getApexChartData();
    },    
    ...mapState({
      bvMobile: state => state.bvMobile,
      bvEnergy: state => state.bvEnergy,
      pointEnergy: state => state.pointEnergy,
      pointMobile: state => state.pointMobile,
      iboRegistryFee: state => state.iboRegistryFee,
      iboRenewalFee: state => state.iboRenewalFee,
      teamConfigs: state => state.teamConfigs,
      personalConfigs: state => state.personalConfigs,
    }),    
  },  
  methods: {
    getOrgChartData(teamConfig) {

      console.log('getOrgChartData', teamConfig)

      if (teamConfig) {

        if (teamConfig.layer == 1) {
          return [
            ['Head', ''],
            ['Tail', 'Head'],
          ]          
        } else if (teamConfig.layer == 2) {
          return [
            ['Head', ''],
            ['L1', 'Head'],
            ['Tail', 'L1'],
          ]    
        } else if (teamConfig.layer == 3) {
          return [
            ['Head', ''],
            ['L1', 'Head'],
            ['L2', 'L1'],
            ['Tail', 'L2'],
          ]    
        } else if (teamConfig.layer == 4) {
          return [
            ['Head', ''],
            ['L1', 'Head'],
            ['L2', 'L1'],
            ['L3', 'L2'],
            ['Tail', 'L3'],
          ]    
        } else if (teamConfig.layer == 5) {
          return [
            ['Head', ''],
            ['L1', 'Head'],
            ['L2', 'L1'],
            ['L3', 'L2'],
            ['L4', 'L3'],
            ['Tail', 'L4'],
          ]    
        } else if (teamConfig.layer == 6) {
          return [
            ['Head', ''],
            ['L1', 'Head'],
            ['L2', 'L1'],
            ['L3', 'L2'],
            ['L4', 'L3'],
            ['L5', 'L4'],
            ['Tail', 'L5'],
          ]    
        } else if (teamConfig.layer == 7) {
          return [
            ['Head', ''],
            ['L1', 'Head'],
            ['L2', 'L1'],
            ['L3', 'L2'],
            ['L4', 'L3'],
            ['L5', 'L4'],
            ['L6', 'L5'],
            ['Tail', 'L6'],
          ]    
        } else {
          return [['Head', '']]
        }
        

      } else {
        return [['Head', '']]
      }
    },   

   	drawChart(teamConfig) {
      this.orgChartData = new google.visualization.DataTable()
      this.orgChartData.addColumn('string', 'Level')
      this.orgChartData.addColumn('string', 'Sponsor')

      const layerOrgChartData = this.getOrgChartData(teamConfig)
      console.log('layerOrgChartData', layerOrgChartData)
      // For each orgchart box, provide the name, manager, and tooltip to show.
      this.orgChartData.addRows(layerOrgChartData)

			// Create the chart.
      const chart = new google.visualization.OrgChart(document.getElementById('tree'));
      
      // Draw the chart, setting the allowHtml option to true for the tooltips.
      chart.draw(this.orgChartData, {allowHtml:true});

    },  	
  	getTotalCommissions() {
  		const headCommission = this.headCommission
  		const tailCommission = this.tailCommission

      return tailCommission.personalMobile + tailCommission.teamMobile + tailCommission.personalEnergy + tailCommission.teamEnergy + headCommission.personalMobile + headCommission.teamMobile + headCommission.personalEnergy + headCommission.teamEnergy
  	},  
  	getGcChartData() {
  		const headTailCounts = this.headTailCounts
  		const headCommission = this.headCommission
  		const tailCommission = this.tailCommission
  		const totalCommission = this.totalCommission

  		// console.log('headCommission', headCommission)
  		// console.log('tailCommission', tailCommission)

      return [
        ['Commission Layer', 'Personal Energy', 'Personal Mobile', 'Team Energy', 'Team Mobile', 'Total Energy', 'Total Mobile'],
        [`Head Total ${headCommission.personalMobile + headCommission.teamMobile + headCommission.personalEnergy + headCommission.teamEnergy}`, headCommission.personalEnergy, headCommission.personalMobile, headCommission.teamEnergy, headCommission.teamMobile, 0, 0],
        [`Tail Total ${tailCommission.personalMobile + tailCommission.teamMobile + tailCommission.personalEnergy + tailCommission.teamEnergy}`, tailCommission.personalEnergy, tailCommission.personalMobile, tailCommission.teamEnergy, tailCommission.teamMobile, 0, 0],
        [`Grand Total ${totalCommission}`, 0, 0, 0, 0, `${tailCommission.personalEnergy + tailCommission.teamEnergy + headCommission.personalEnergy + headCommission.teamEnergy}`, `${tailCommission.personalMobile + tailCommission.teamMobile + headCommission.personalMobile + headCommission.teamMobile}`],
      ]


  	},
    getApexChartData() {
      const headTailCounts = this.headTailCounts
      const headCommission = this.headCommission
      const tailCommission = this.tailCommission
      const totalCommission = this.totalCommission

      return [{
        name: 'Personal Energy',
        data: [headCommission.personalEnergy, tailCommission.personalEnergy, 0]
      }, {
        name: 'Personal Mobile',
        data: [headCommission.personalMobile, tailCommission.personalMobile, 0]
      }, {
        name: 'Team Energy',
        data: [headCommission.teamEnergy, tailCommission.teamEnergy, 0]
      }, {
        name: 'Team Mobile',
        data: [headCommission.teamMobile, tailCommission.teamMobile, 0]
      }, {
        name: 'Total Energy',
        data: [0, 0, tailCommission.personalEnergy + tailCommission.teamEnergy + headCommission.personalEnergy + headCommission.teamEnergy]
      }, {
        name: 'Total Mobile',
        data: [0, 0, tailCommission.personalMobile + tailCommission.teamMobile + headCommission.personalMobile + headCommission.teamMobile]
      }]


    },    
  	getHeadTailCounts() {
			let headMobileCount = 0
			let tailMobileCount = 0
			let headEnergyCount = 0
			let tailEnergyCount = 0

  		if (this.mobileCount * this.pointMobile >= this.teamCommissionPoint) {
  			headMobileCount = Math.ceil(this.teamCommissionPoint / this.pointMobile)
  			tailMobileCount = this.mobileCount - headMobileCount
  			headEnergyCount = 0
  			tailEnergyCount = this.energyCount
  		} else {
  			headMobileCount = this.mobileCount
  			tailMobileCount = 0
  			const headEnergyCountNeeded = Math.ceil((this.teamCommissionPoint - headMobileCount * this.pointMobile) / this.pointEnergy)

  			if (this.energyCount > headEnergyCountNeeded) {
  				headEnergyCount = headEnergyCountNeeded
  				tailEnergyCount = this.energyCount - headEnergyCount	
  			} else {
  				headEnergyCount = this.energyCount
  			}
  		}

  		const rtn = {
  			headMobileCount,
  			tailMobileCount,
  			headEnergyCount,
  			tailEnergyCount
  		}

  		console.log('getHeadTailCounts', rtn)

  		return rtn

  	},
  	getHeadCommission({headMobileCount, tailMobileCount, headEnergyCount, tailEnergyCount}) {
  		let personalMobile = 0
  		if (headMobileCount > 0) {
  			console.log('this.personalPercent', this.personalPercent)
  			personalMobile = headMobileCount * this.mobileRate * this.bvMobile * this.personalPercent.head
  		}

  		let teamMobile = 0
  		if (tailMobileCount > 0) {
  			teamMobile = tailMobileCount * this.mobileRate * this.bvMobile * this.teamCommissionPercent
  		}

  		let personalEnergy = 0
  		if (headEnergyCount > 0) {
  			personalEnergy = headEnergyCount * this.energyRate * this.bvEnergy * this.personalPercent.head
  		}

  		let teamEnergy = 0
  		if (tailEnergyCount > 0) {
  			teamEnergy = tailEnergyCount * this.energyRate * this.bvEnergy * this.teamCommissionPercent
  		}

  		return {
  			personalMobile,
  			teamMobile,
  			personalEnergy,
  			teamEnergy
  		}	
  	},  	
  	getTailCommission({headMobileCount, tailMobileCount, headEnergyCount, tailEnergyCount}) {
  		let personalMobile = 0
  		if (tailMobileCount > 0) {
  			personalMobile = tailMobileCount * this.mobileRate * this.bvMobile * this.personalPercent.tail
  		}

  		let teamMobile = 0

  		let personalEnergy = 0
  		if (tailEnergyCount > 0) {
  			personalEnergy = tailEnergyCount * this.energyRate * this.bvEnergy * this.personalPercent.tail
  		}

  		let teamEnergy = 0

  		return {
  			personalMobile,
  			teamMobile,
  			personalEnergy,
  			teamEnergy
  		}	
  	},
  	getPersonalConfig(personalPoint) {
    	const myPersonalConfigs = this.personalConfigs.filter(personalConfig => {
    		if (personalConfig.to) {
    			if (personalPoint >= personalConfig.from && personalPoint <= personalConfig.to) {
    				return true
    			}	
    		} else {
    			if (personalPoint >= personalConfig.from) {
    				return true
    			}
    		}
    	})

    	return myPersonalConfigs[0]
  	}

  },
}
</script>